const initialState = { selectedTab: 'overview', isLoading: false, hasError: false };

function tabReducer(state, action) {
  switch (action.type) {
    case 'SELECT_TAB':
      return { ...state, selectedTab: action.tab, hasError: false };
    case 'FETCH_START':
      return { ...state, isLoading: true, hasError: false };
    case 'FETCH_SUCCESS':
      return { ...state, isLoading: false };
    case 'FETCH_ERROR':
      return { ...state, isLoading: false, hasError: true };
    default:
      return state;
  }
}

function TabbedView({ tabs }) {
  const [state, dispatch] = useReducer(tabReducer, initialState);
  const { selectedTab, isLoading, hasError } = state;

  function handleTabClick(tab) {
    dispatch({ type: 'SELECT_TAB', tab });
  }

  return (
    <div>
      <nav>
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => handleTabClick(tab.id)}
            aria-selected={selectedTab === tab.id}
          >
            {tab.label}
          </button>
        ))}
      </nav>
      {isLoading && <p>Loading...</p>}
      {hasError && <p>Something went wrong.</p>}
    </div>
  );
}
